app/api/weather/route.ts.content:
import type { NextRequest } from "next/server"
import { json, withTimeout, rateLimit, clientKey } from "@/lib/api/http"
import { env } from "@/lib/api/env"
import { conditionLabel, mockWeather } from "@/lib/api/mock"
import type { WeatherCondition, WeatherResponse, WeatherDay } from "@/lib/api/types"

export const dynamic = "force-dynamic"

const DOW = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"]

function wmoToCondition(code: number): WeatherCondition {
  if (code === 0) return "sunny"
  if (code === 1 || code === 2) return "partly-cloudy"
  if (code === 3) return "cloudy"
  if (code === 45 || code === 48) return "foggy"
  if ((code >= 51 && code <= 67) || (code >= 80 && code <= 82)) return "rainy"
  if ((code >= 71 && code <= 77) || code === 85 || code === 86) return "snowy"
  if (code >= 95 && code <= 99) return "stormy"
  return "partly-cloudy"
}

/** Format an ISO-ish timestamp ("2026-06-18T06:12") to "HH:MM" in local terms. */
function toHHMM(value: string | undefined): string {
  if (!value) return "--:--"
  const m = /T(\d{2}):(\d{2})/.exec(value)
  if (m) return `${m[1]}:${m[2]}`
  const d = new Date(value)
  if (Number.isNaN(d.getTime())) return "--:--"
  return `${String(d.getHours()).padStart(2, "0")}:${String(d.getMinutes()).padStart(2, "0")}`
}

/** Map a daily date string ("2026-06-18") to a day label. */
function dayLabel(dateStr: string, index: number): string {
  if (index === 0) return "Today"
  const d = new Date(`${dateStr}T00:00:00`)
  if (Number.isNaN(d.getTime())) return dateStr
  return DOW[d.getDay()]
}

interface GeoResult {
  name: string
  country?: string
  latitude: number
  longitude: number
}

/** Reverse-geocode coordinates to a place name (Open-Meteo is forward-only).
 * Uses Nominatim (OSM) — keyless, works server-side with a User-Agent. Returns {} on failure. */
async function reverseGeocode(
  lat: number,
  lon: number,
  signal: AbortSignal,
): Promise<{ name?: string; country?: string }> {
  try {
    const url = `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lon}&format=json&zoom=10&addressdetails=1`
    const res = await fetch(url, {
      signal,
      headers: { "User-Agent": "apple-techie-macos/1.0 (https://appletechie.dev)" },
    })
    if (!res.ok) return {}
    const b = (await res.json()) as {
      name?: string
      address?: {
        city?: string
        town?: string
        village?: string
        county?: string
        state?: string
        country?: string
        country_code?: string
      }
    }
    const a = b.address ?? {}
    const name = a.city || a.town || a.village || a.county || b.name || a.state || undefined
    return { name, country: a.country || (a.country_code ? a.country_code.toUpperCase() : undefined) }
  } catch {
    return {}
  }
}

export async function GET(req: NextRequest) {
  const { searchParams } = new URL(req.url)
  const city = searchParams.get("city")?.trim() || ""
  const latParam = searchParams.get("lat")
  const lonParam = searchParams.get("lon")

  if (!rateLimit(clientKey(req, "weather"), 60, 60_000)) {
    return json(mockWeather(city || "Cupertino"), "mock")
  }

  try {
    const payload = await withTimeout<WeatherResponse>(async (signal) => {
      let lat: number
      let lon: number
      let name: string
      let country: string | undefined

      if (city) {
        const geoUrl = new URL(env.geocodeBase)
        geoUrl.searchParams.set("name", city)
        geoUrl.searchParams.set("count", "1")
        const geoRes = await fetch(geoUrl, { signal })
        if (!geoRes.ok) throw new Error(`geocode ${geoRes.status}`)
        const geoBody = (await geoRes.json()) as { results?: GeoResult[] }
        const hit = geoBody.results?.[0]
        if (!hit) throw new Error("no geocode result")
        lat = hit.latitude
        lon = hit.longitude
        name = hit.name
        country = hit.country
      } else {
        const latNum = Number(latParam)
        const lonNum = Number(lonParam)
        if (!Number.isFinite(latNum) || !Number.isFinite(lonNum)) {
          throw new Error("missing coordinates")
        }
        lat = latNum
        lon = lonNum
        const rev = await reverseGeocode(latNum, lonNum, signal)
        name = rev.name || `${latNum.toFixed(2)}, ${lonNum.toFixed(2)}`
        country = rev.country
      }

      const wUrl = new URL(env.weatherBase)
      wUrl.searchParams.set("latitude", String(lat))
      wUrl.searchParams.set("longitude", String(lon))
      wUrl.searchParams.set(
        "current",
        "temperature_2m,relative_humidity_2m,apparent_temperature,is_day,weather_code,wind_speed_10m",
      )
      wUrl.searchParams.set(
        "daily",
        "weather_code,temperature_2m_max,temperature_2m_min,sunrise,sunset",
      )
      wUrl.searchParams.set("timezone", "auto")
      wUrl.searchParams.set("forecast_days", "5")

      const wRes = await fetch(wUrl, { signal })
      if (!wRes.ok) throw new Error(`weather ${wRes.status}`)
      const w = (await wRes.json()) as {
        current?: {
          temperature_2m: number
          relative_humidity_2m: number
          apparent_temperature: number
          is_day: number
          weather_code: number
          wind_speed_10m: number
        }
        daily?: {
          time: string[]
          weather_code: number[]
          temperature_2m_max: number[]
          temperature_2m_min: number[]
          sunrise: string[]
          sunset: string[]
        }
      }

      const cur = w.current
      const daily = w.daily
      if (!cur || !daily || !Array.isArray(daily.time) || daily.time.length === 0) {
        throw new Error("malformed weather payload")
      }

      const currentCondition = wmoToCondition(cur.weather_code)

      const forecast: WeatherDay[] = daily.time.slice(0, 5).map((dateStr, i) => ({
        day: dayLabel(dateStr, i),
        date: dateStr,
        high: Math.round(daily.temperature_2m_max[i]),
        low: Math.round(daily.temperature_2m_min[i]),
        condition: wmoToCondition(daily.weather_code[i]),
      }))

      return {
        location: { name, country, lat, lon },
        current: {
          tempC: Math.round(cur.temperature_2m),
          feelsLikeC: Math.round(cur.apparent_temperature),
          condition: currentCondition,
          conditionLabel: conditionLabel(currentCondition),
          humidity: Math.round(cur.relative_humidity_2m),
          windKph: Math.round(cur.wind_speed_10m),
          sunrise: toHHMM(daily.sunrise[0]),
          sunset: toHHMM(daily.sunset[0]),
          isDay: cur.is_day === 1,
        },
        forecast,
        updatedAt: new Date().toISOString(),
      }
    }, 4500)

    return json(payload, "live")
  } catch {
    return json(mockWeather(city || "Cupertino"), "mock")
  }
}

app/globals.css.content:
@tailwind base;
@tailwind components;
@tailwind utilities;

/* ============================================================================
   macOS Tahoe — Liquid Glass design system (single source of truth)
   - (A) shadcn semantic HSL tokens (light + dark)
   - (B) Liquid Glass material tokens (--lg-*)
   - (C) base resets + system font
   Components live in @layer components below.
   ========================================================================== */

@layer base {
  :root {
    /* (A) shadcn semantic tokens — neutral base */
    --background: 0 0% 100%;
    --foreground: 0 0% 3.9%;
    --card: 0 0% 100%;
    --card-foreground: 0 0% 3.9%;
    --popover: 0 0% 100%;
    --popover-foreground: 0 0% 3.9%;
    --primary: 0 0% 9%;
    --primary-foreground: 0 0% 98%;
    --secondary: 0 0% 96.1%;
    --secondary-foreground: 0 0% 9%;
    --muted: 0 0% 96.1%;
    --muted-foreground: 0 0% 45.1%;
    --accent: 0 0% 96.1%;
    --accent-foreground: 0 0% 9%;
    --destructive: 0 84.2% 60.2%;
    --destructive-foreground: 0 0% 98%;
    --border: 0 0% 89.8%;
    --input: 0 0% 89.8%;
    --ring: 211 100% 50%;
    --chart-1: 12 76% 61%;
    --chart-2: 173 58% 39%;
    --chart-3: 197 37% 24%;
    --chart-4: 43 74% 66%;
    --chart-5: 27 87% 67%;
    --radius: 0.5rem;
    --sidebar-background: 0 0% 98%;
    --sidebar-foreground: 240 5.3% 26.1%;
    --sidebar-primary: 240 5.9% 10%;
    --sidebar-primary-foreground: 0 0% 98%;
    --sidebar-accent: 240 4.8% 95.9%;
    --sidebar-accent-foreground: 240 5.9% 10%;
    --sidebar-border: 220 13% 91%;
    --sidebar-ring: 217.2 91.2% 59.8%;

    /* (B) Liquid Glass material — light */
    /* Tahoe Liquid Glass is genuinely translucent — keep tints low, lean on blur */
    --lg-blur-thin: 12px;
    --lg-blur: 30px;
    --lg-blur-thick: 44px;
    --lg-blur-chrome: 32px;
    --lg-saturate: 170%;
    --lg-brightness-light: 1.04;
    --lg-brightness-dark: 1.32;

    --lg-tint: rgba(255, 255, 255, 0.30);
    --lg-tint-thin: rgba(255, 255, 255, 0.18);
    --lg-tint-thick: rgba(255, 255, 255, 0.44);
    --lg-tint-clear: rgba(255, 255, 255, 0.07);

    --lg-highlight-top: rgba(255, 255, 255, 0.5);
    --lg-rim: rgba(255, 255, 255, 0.26);
    --lg-inner-shadow: rgba(0, 0, 0, 0.035);

    --lg-shadow-sm: 0 1px 3px rgba(0, 0, 0, 0.06);
    --lg-shadow: 0 6px 20px rgba(0, 0, 0, 0.09);
    --lg-shadow-lg: 0 12px 40px rgba(0, 0, 0, 0.15);

    --lg-r-window: 20px;
    --lg-r-card: 16px;
    --lg-r-chrome: 14px;
    --lg-r-control: 8px;
    --lg-r-tile: 20px;
    --lg-r-dock: 22px;
    --lg-r-menu: 10px;
    --lg-pad: 8px;

    --lg-accent: #007aff;
    --lg-accent-press: #0063cc;
    --lg-accent-tint: rgba(0, 122, 255, 0.22);

    --lg-label: rgba(0, 0, 0, 0.85);
    --lg-label-secondary: rgba(0, 0, 0, 0.50);
    --lg-label-tertiary: rgba(0, 0, 0, 0.26);

    --lg-ease-spring: linear(0, 0.009, 0.035 2.1%, 0.141, 0.281 6.7%, 0.723 12.9%, 0.938, 1.077, 1.149 24.3%, 1.143, 1.089 35%, 1.013 44.2%, 0.984 56.4%, 1 73%, 1.001);
    --lg-ease-out: cubic-bezier(0.32, 0.72, 0, 1);
    --lg-ease-press: cubic-bezier(0.4, 0, 0.2, 1);
    --lg-dur-fast: 180ms;
    --lg-dur: 320ms;
    --lg-dur-slow: 480ms;
  }

  .dark {
    --background: 0 0% 7%;
    --foreground: 0 0% 98%;
    --card: 0 0% 9%;
    --card-foreground: 0 0% 98%;
    --popover: 0 0% 9%;
    --popover-foreground: 0 0% 98%;
    --primary: 0 0% 98%;
    --primary-foreground: 0 0% 9%;
    --secondary: 0 0% 14.9%;
    --secondary-foreground: 0 0% 98%;
    --muted: 0 0% 14.9%;
    --muted-foreground: 0 0% 63.9%;
    --accent: 0 0% 14.9%;
    --accent-foreground: 0 0% 98%;
    --destructive: 0 62.8% 30.6%;
    --destructive-foreground: 0 0% 98%;
    --border: 0 0% 18%;
    --input: 0 0% 18%;
    --ring: 211 92% 60%;
    --chart-1: 220 70% 50%;
    --chart-2: 160 60% 45%;
    --chart-3: 30 80% 55%;
    --chart-4: 280 65% 60%;
    --chart-5: 340 75% 55%;
    --sidebar-background: 240 5.9% 10%;
    --sidebar-foreground: 240 4.8% 95.9%;
    --sidebar-primary: 224.3 76.3% 48%;
    --sidebar-primary-foreground: 0 0% 100%;
    --sidebar-accent: 240 3.7% 15.9%;
    --sidebar-accent-foreground: 240 4.8% 95.9%;
    --sidebar-border: 240 3.7% 15.9%;
    --sidebar-ring: 217.2 91.2% 59.8%;

    /* (B) Liquid Glass material — dark (translucent, soft) */
    --lg-tint: rgba(28, 28, 30, 0.42);
    --lg-tint-thin: rgba(28, 28, 30, 0.28);
    --lg-tint-thick: rgba(22, 22, 24, 0.55);
    --lg-tint-clear: rgba(0, 0, 0, 0.12);

    --lg-highlight-top: rgba(255, 255, 255, 0.16);
    --lg-rim: rgba(255, 255, 255, 0.10);
    --lg-inner-shadow: rgba(0, 0, 0, 0.22);

    --lg-shadow-sm: 0 1px 3px rgba(0, 0, 0, 0.30);
    --lg-shadow: 0 6px 20px rgba(0, 0, 0, 0.40);
    --lg-shadow-lg: 0 12px 40px rgba(0, 0, 0, 0.52);

    --lg-accent: #0a84ff;
    --lg-accent-press: #4aa3ff;
    --lg-accent-tint: rgba(10, 132, 255, 0.30);

    --lg-label: rgba(255, 255, 255, 0.92);
    --lg-label-secondary: rgba(255, 255, 255, 0.55);
    --lg-label-tertiary: rgba(255, 255, 255, 0.28);
  }

  /* (C) base resets */
  * {
    @apply border-border;
  }

  html,
  body {
    height: 100%;
  }

  body {
    @apply bg-background text-foreground;
    font-family: -apple-system, BlinkMacSystemFont, "SF Pro Text", "SF Pro Display",
      "Inter var", "Segoe UI", system-ui, sans-serif;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    text-rendering: optimizeLegibility;
    font-feature-settings: "cv02", "cv03", "cv04", "cv11";
    overflow: hidden;
    overscroll-behavior: none;
  }

  /* Tahoe selection */
  ::selection {
    background: var(--lg-accent-tint);
  }
}

/* ============================================================================
   Liquid Glass component utilities
   - Base material classes are STATIC (no transform) so chrome stays stable.
   - Compose `.glass-interactive` for hover-lift + press on buttons/tiles.
   ========================================================================== */

@layer components {
  .glass,
  .glass-thin,
  .glass-thick,
  .glass-chrome,
  .glass-clear {
    position: relative;
    isolation: isolate;
    transition: transform var(--lg-dur-fast) var(--lg-ease-out),
      box-shadow var(--lg-dur-fast) var(--lg-ease-out),
      background var(--lg-dur) var(--lg-ease-out);
  }

  .glass {
    background: var(--lg-tint);
    -webkit-backdrop-filter: blur(var(--lg-blur)) saturate(var(--lg-saturate)) brightness(var(--lg-brightness-light));
    backdrop-filter: blur(var(--lg-blur)) saturate(var(--lg-saturate)) brightness(var(--lg-brightness-light));
    border-radius: var(--lg-r-card);
    box-shadow:
      inset 0 1px 0 0 var(--lg-highlight-top),
      inset 0 0 0 0.5px var(--lg-rim),
      inset 0 -8px 16px -12px var(--lg-inner-shadow),
      var(--lg-shadow);
  }

  .glass-thin {
    background: var(--lg-tint-thin);
    -webkit-backdrop-filter: blur(var(--lg-blur-thin)) saturate(var(--lg-saturate));
    backdrop-filter: blur(var(--lg-blur-thin)) saturate(var(--lg-saturate));
    border-radius: var(--lg-r-menu);
    box-shadow:
      inset 0 1px 0 0 var(--lg-highlight-top),
      inset 0 0 0 0.5px var(--lg-rim),
      var(--lg-shadow-sm);
  }

  .glass-thick {
    background: var(--lg-tint-thick);
    -webkit-backdrop-filter: blur(var(--lg-blur-thick)) saturate(var(--lg-saturate));
    backdrop-filter: blur(var(--lg-blur-thick)) saturate(var(--lg-saturate));
    border-radius: var(--lg-r-tile);
    box-shadow:
      inset 0 1.5px 0 0 var(--lg-highlight-top),
      inset 0 0 0 0.5px var(--lg-rim),
      inset 0 -12px 24px -16px var(--lg-inner-shadow),
      var(--lg-shadow-lg);
  }

  .glass-chrome {
    background: var(--lg-tint);
    -webkit-backdrop-filter: blur(var(--lg-blur-chrome)) saturate(var(--lg-saturate)) brightness(var(--lg-brightness-light));
    backdrop-filter: blur(var(--lg-blur-chrome)) saturate(var(--lg-saturate)) brightness(var(--lg-brightness-light));
    border-radius: var(--lg-r-dock);
    box-shadow:
      inset 0 1px 0 0 var(--lg-highlight-top),
      inset 0 0 0 0.5px var(--lg-rim),
      var(--lg-shadow-lg);
  }

  .glass-clear {
    background: var(--lg-tint-clear);
    -webkit-backdrop-filter: blur(6px) saturate(120%);
    backdrop-filter: blur(6px) saturate(120%);
    border-radius: var(--lg-r-menu);
    box-shadow:
      inset 0 1px 0 0 rgba(255, 255, 255, 0.35),
      inset 0 0 0 1px rgba(255, 255, 255, 0.18),
      var(--lg-shadow-sm);
  }

  .dark .glass,
  .dark .glass-chrome {
    -webkit-backdrop-filter: blur(var(--lg-blur)) saturate(var(--lg-saturate)) brightness(var(--lg-brightness-dark));
    backdrop-filter: blur(var(--lg-blur)) saturate(var(--lg-saturate)) brightness(var(--lg-brightness-dark));
  }

  /* specular sheen */
  .glass::before,
  .glass-thick::before,
  .glass-chrome::before {
    content: "";
    position: absolute;
    inset: 0;
    border-radius: inherit;
    pointer-events: none;
    z-index: 0;
    background: linear-gradient(
      135deg,
      rgba(255, 255, 255, 0.35) 0%,
      rgba(255, 255, 255, 0) 30%,
      rgba(255, 255, 255, 0) 74%,
      rgba(255, 255, 255, 0.10) 100%
    );
    opacity: 0.3;
    mix-blend-mode: screen;
    transition: opacity var(--lg-dur) var(--lg-ease-out);
  }
  .glass > *,
  .glass-thick > *,
  .glass-chrome > * {
    position: relative;
    z-index: 1;
  }

  /* interactive modifier: lift on hover, press on active */
  .glass-interactive {
    cursor: pointer;
  }
  .glass-interactive:hover {
    transform: translateY(-1px);
  }
  .glass-interactive:hover::before {
    opacity: 0.5;
  }
  .glass-interactive:active {
    transform: scale(0.97);
    filter: brightness(0.96);
    transition-duration: 100ms;
    transition-timing-function: var(--lg-ease-press);
  }

  /* helpers */
  .glass-tint-accent {
    background: var(--lg-accent-tint);
  }
  .glass-nest > * {
    border-radius: calc(var(--lg-r-card) - var(--lg-pad));
  }
  .glass-inactive {
    -webkit-backdrop-filter: blur(var(--lg-blur)) saturate(100%);
    backdrop-filter: blur(var(--lg-blur)) saturate(100%);
    opacity: 0.92;
  }

  /* vibrancy text */
  .lg-vibrant {
    color: var(--lg-label);
  }
  .lg-vibrant-secondary {
    color: var(--lg-label-secondary);
  }
  .lg-vibrant-tertiary {
    color: var(--lg-label-tertiary);
  }
  /* legible text directly over wallpaper (menubar, login, launchpad) */
  .lg-text-scrim {
    color: #fff;
    text-shadow: 0 0 1px rgba(0, 0, 0, 0.35), 0 1px 2px rgba(0, 0, 0, 0.25);
  }

  /* focus ring */
  .lg-focus:focus-visible {
    outline: none;
    box-shadow: 0 0 0 3px color-mix(in srgb, var(--lg-accent) 45%, transparent);
  }

  /* shake (wrong password) */
  @keyframes lg-shake {
    0%, 100% { transform: translateX(0); }
    20% { transform: translateX(-8px); }
    40% { transform: translateX(8px); }
    60% { transform: translateX(-5px); }
    80% { transform: translateX(5px); }
  }
  .lg-shake {
    animation: lg-shake 0.42s var(--lg-ease-press);
  }

  /* glass "flex/jiggle" on appear */
  @keyframes lg-flex {
    0% {
      transform: scale(0.92);
    }
    55% {
      transform: scale(1.04);
    }
    100% {
      transform: scale(1);
    }
  }
  .lg-flex {
    animation: lg-flex var(--lg-dur) var(--lg-ease-spring);
  }

  /* refractive lensing — progressive enhancement only where supported */
  @supports (backdrop-filter: blur(1px)) and (filter: url("#lg-lens")) {
    .glass-lens {
      -webkit-backdrop-filter: blur(var(--lg-blur)) saturate(var(--lg-saturate)) url("#lg-lens");
      backdrop-filter: blur(var(--lg-blur)) saturate(var(--lg-saturate)) url("#lg-lens");
    }
  }
}

/* ============================================================================
   Scrollbars (macOS overlay style)
   ========================================================================== */
::-webkit-scrollbar {
  width: 9px;
  height: 9px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background: color-mix(in srgb, currentColor 28%, transparent);
  border-radius: 5px;
  border: 2px solid transparent;
  background-clip: content-box;
}
::-webkit-scrollbar-thumb:hover {
  background: color-mix(in srgb, currentColor 45%, transparent);
  background-clip: content-box;
}

/* ============================================================================
   Accessibility — honor user preferences (required)
   ========================================================================== */
@media (prefers-reduced-transparency: reduce) {
  .glass,
  .glass-thin,
  .glass-thick,
  .glass-chrome,
  .glass-clear {
    -webkit-backdrop-filter: none;
    backdrop-filter: none;
    background: color-mix(in srgb, var(--lg-tint) 100%, white 18%);
  }
  .dark .glass,
  .dark .glass-thin,
  .dark .glass-thick,
  .dark .glass-chrome,
  .dark .glass-clear {
    background: color-mix(in srgb, var(--lg-tint) 100%, black 22%);
  }
}

@media (prefers-contrast: more) {
  .glass,
  .glass-thin,
  .glass-thick,
  .glass-chrome {
    box-shadow: inset 0 0 0 1px currentColor, var(--lg-shadow);
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
  .lg-flex {
    animation: none;
  }
}

