"use client"

import { useState, useEffect } from "react"
import { SystemProvider, useSystem } from "@/components/system-provider"
import BootScreen from "@/components/boot-screen"
import LoginScreen from "@/components/login-screen"
import Desktop from "@/components/desktop"
import SleepScreen from "@/components/sleep-screen"
import ShutdownScreen from "@/components/shutdown-screen"

type SystemState = "booting" | "login" | "desktop" | "sleeping" | "shutdown" | "restarting"

function Shell() {
  const { brightness, isDarkMode, toggleDarkMode } = useSystem()
  const [systemState, setSystemState] = useState<SystemState>("booting")

  useEffect(() => {
    if (systemState === "booting" || systemState === "restarting") {
      const timer = setTimeout(() => setSystemState("login"), 3000)
      return () => clearTimeout(timer)
    }
  }, [systemState])

  const renderScreen = () => {
    switch (systemState) {
      case "booting":
      case "restarting":
        return <BootScreen />
      case "login":
        return (
          <LoginScreen
            onLogin={() => setSystemState("desktop")}
            isDarkMode={isDarkMode}
            onToggleDarkMode={toggleDarkMode}
          />
        )
      case "desktop":
        return (
          <Desktop
            onLogout={() => setSystemState("login")}
            onSleep={() => setSystemState("sleeping")}
            onShutdown={() => setSystemState("shutdown")}
            onRestart={() => setSystemState("restarting")}
          />
        )
      case "sleeping":
        return <SleepScreen onWakeUp={() => setSystemState("login")} isDarkMode={isDarkMode} />
      case "shutdown":
        return <ShutdownScreen onBoot={() => setSystemState("booting")} />
      default:
        return <BootScreen />
    }
  }

  // brightness: 100% => no dim, 10% => ~0.81 dim
  const dim = Math.max(0, ((100 - brightness) / 100) * 0.9)

  return (
    <div className="relative h-screen w-screen overflow-hidden bg-black">
      {renderScreen()}
      <div
        className="pointer-events-none fixed inset-0 z-[9999] bg-black transition-opacity duration-300"
        style={{ opacity: dim }}
        aria-hidden
      />
    </div>
  )
}

export default function Home() {
  return (
    <SystemProvider>
      <Shell />
    </SystemProvider>
  )
}

components/apps/facetime.tsx.content:
"use client"

import { useCallback, useEffect, useRef, useState } from "react"
import {
  Mic,
  MicOff,
  Video,
  VideoOff,
  PhoneOff,
  Maximize2,
  Minimize2,
  AlertTriangle,
  ShieldAlert,
  CameraOff,
  Loader2,
} from "lucide-react"
import { cn } from "@/lib/utils"

interface FaceTimeProps {
  isDarkMode?: boolean
}

type CallStatus = "idle" | "connecting" | "active"

type CallError = {
  kind: "denied" | "no-device" | "insecure" | "unsupported" | "in-use" | "generic"
  message: string
}

const CONTACT_NAME = "apple-techie"
const CONTACT_HANDLE = "mail@appletechie.dev"
const CONTACT_INITIALS = "DP"

function formatDuration(totalSeconds: number) {
  const h = Math.floor(totalSeconds / 3600)
  const m = Math.floor((totalSeconds % 3600) / 60)
  const s = totalSeconds % 60
  const mm = m.toString().padStart(2, "0")
  const ss = s.toString().padStart(2, "0")
  return h > 0 ? `${h}:${mm}:${ss}` : `${m}:${ss}`
}

export default function FaceTime({ isDarkMode = true }: FaceTimeProps) {
  const [status, setStatus] = useState<CallStatus>("idle")
  const [error, setError] = useState<CallError | null>(null)
  const [seconds, setSeconds] = useState(0)
  const [isMuted, setIsMuted] = useState(false)
  const [isCameraOff, setIsCameraOff] = useState(false)
  const [isExpanded, setIsExpanded] = useState(false)

  const videoRef = useRef<HTMLVideoElement>(null)
  const streamRef = useRef<MediaStream | null>(null)

  const supportsMedia =
    typeof navigator !== "undefined" && !!navigator.mediaDevices?.getUserMedia

  const stopStream = useCallback(() => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach((track) => track.stop())
      streamRef.current = null
    }
    if (videoRef.current) {
      videoRef.current.srcObject = null
    }
  }, [])

  // Tear down the camera on unmount — no lingering tracks.
  useEffect(() => stopStream, [stopStream])

  // Call timer.
  useEffect(() => {
    if (status !== "active") return
    const id = window.setInterval(() => setSeconds((s) => s + 1), 1000)
    return () => window.clearInterval(id)
  }, [status])

  const startCall = useCallback(async () => {
    setError(null)

    if (!supportsMedia) {
      setError({
        kind: "unsupported",
        message:
          "This browser does not support camera access. Try a recent version of Safari, Chrome, or Edge.",
      })
      return
    }

    // getUserMedia is only available in secure contexts (https or localhost).
    if (typeof window !== "undefined" && window.isSecureContext === false) {
      setError({
        kind: "insecure",
        message:
          "Camera access requires a secure connection (HTTPS). Open this page over HTTPS to start a video call.",
      })
      return
    }

    setStatus("connecting")
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: "user" },
        audio: true,
      })
      streamRef.current = stream
      if (videoRef.current) {
        videoRef.current.srcObject = stream
      }
      // Reflect any prior toggle preferences onto the fresh tracks.
      stream.getAudioTracks().forEach((t) => (t.enabled = !isMuted))
      stream.getVideoTracks().forEach((t) => (t.enabled = !isCameraOff))
      setSeconds(0)
      setStatus("active")
    } catch (err) {
      setStatus("idle")
      stopStream()
      const name = err instanceof Error ? err.name : ""
      if (name === "NotAllowedError" || name === "SecurityError") {
        setError({
          kind: "denied",
          message:
            "Camera and microphone access was denied. Allow access in your browser settings, then try again.",
        })
      } else if (name === "NotFoundError" || name === "OverconstrainedError") {
        setError({
          kind: "no-device",
          message: "No camera was found on this device.",
        })
      } else if (name === "NotReadableError") {
        setError({
          kind: "in-use",
          message:
            "Your camera is already in use by another app. Close it and try again.",
        })
      } else {
        setError({
          kind: "generic",
          message: "Could not start the video call. Please try again.",
        })
      }
    }
  }, [supportsMedia, isMuted, isCameraOff, stopStream])

  const endCall = useCallback(() => {
    stopStream()
    setStatus("idle")
    setSeconds(0)
    setIsMuted(false)
    setIsCameraOff(false)
    setIsExpanded(false)
  }, [stopStream])

  const toggleMute = useCallback(() => {
    setIsMuted((prev) => {
      const next = !prev
      streamRef.current?.getAudioTracks().forEach((t) => (t.enabled = !next))
      return next
    })
  }, [])

  const toggleCamera = useCallback(() => {
    setIsCameraOff((prev) => {
      const next = !prev
      streamRef.current?.getVideoTracks().forEach((t) => (t.enabled = !next))
      return next
    })
  }, [])

  const errorIcon = (() => {
    switch (error?.kind) {
      case "denied":
        return <ShieldAlert className="h-7 w-7" aria-hidden />
      case "no-device":
      case "in-use":
        return <CameraOff className="h-7 w-7" aria-hidden />
      case "insecure":
      case "unsupported":
      case "generic":
      default:
        return <AlertTriangle className="h-7 w-7" aria-hidden />
    }
  })()

  return (
    <div className="relative flex h-full w-full flex-col bg-background text-foreground">
      <div
        className={cn(
          "relative flex flex-1 items-center justify-center overflow-hidden p-4 transition-[padding] duration-300 ease-glass sm:p-6",
          isExpanded && "p-0 sm:p-0",
        )}
      >
        {/* Call stage */}
        <div
          className={cn(
            "glass relative flex w-full flex-col overflow-hidden rounded-window shadow-glass transition-all duration-300 ease-glass",
            isExpanded ? "h-full max-w-none rounded-none" : "aspect-video max-w-3xl",
          )}
        >
          {/* Live video (mounted during connecting/active so it can bind early) */}
          <video
            ref={videoRef}
            autoPlay
            muted
            playsInline
            aria-label={`Live camera preview for your call with ${CONTACT_NAME}`}
            className={cn(
              "absolute inset-0 h-full w-full -scale-x-100 bg-black object-cover transition-opacity duration-300",
              status === "active" && !isCameraOff ? "opacity-100" : "opacity-0",
            )}
          />

          {/* IDLE — gesture-gated start surface */}
          {status === "idle" && (
            <div className="absolute inset-0 flex flex-col items-center justify-center gap-6 p-6 text-center">
              <div
                className="lg-flex flex h-24 w-24 items-center justify-center rounded-full bg-muted text-2xl font-semibold text-muted-foreground shadow-glass-sm ring-1 ring-border"
                aria-hidden
              >
                {CONTACT_INITIALS}
              </div>
              <div className="space-y-1">
                <h2 className="text-xl font-semibold tracking-tight">{CONTACT_NAME}</h2>
                <p className="text-sm text-muted-foreground">{CONTACT_HANDLE}</p>
              </div>

              {error ? (
                <div
                  role="alert"
                  className="glass-thin flex max-w-sm flex-col items-center gap-3 rounded-control px-5 py-4 text-sm"
                >
                  <span className="text-destructive">{errorIcon}</span>
                  <p className="text-muted-foreground">{error.message}</p>
                  {error.kind !== "unsupported" &&
                    error.kind !== "insecure" &&
                    error.kind !== "no-device" && (
                      <button
                        type="button"
                        onClick={startCall}
                        className="lg-focus glass-interactive mt-1 rounded-control bg-[var(--lg-accent)] px-4 py-1.5 text-sm font-medium text-white"
                      >
                        Try again
                      </button>
                    )}
                </div>
              ) : (
                <button
                  type="button"
                  onClick={startCall}
                  className="lg-focus glass-interactive flex items-center gap-2.5 rounded-full bg-[var(--lg-accent)] px-6 py-3 text-base font-semibold text-white shadow-glass-sm"
                  aria-label={`Start a video call with ${CONTACT_NAME}`}
                >
                  <Video className="h-5 w-5" aria-hidden />
                  Start Video
                </button>
              )}

              {!error && (
                <p className="max-w-xs text-xs text-muted-foreground/80">
                  Your camera and microphone are only requested when you start the call.
                </p>
              )}
            </div>
          )}

          {/* CONNECTING */}
          {status === "connecting" && (
            <div className="absolute inset-0 flex flex-col items-center justify-center gap-4 bg-black/60 text-white lg-text-scrim">
              <div
                className="flex h-20 w-20 items-center justify-center rounded-full bg-white/15 text-xl font-semibold backdrop-blur-glass"
                aria-hidden
              >
                {CONTACT_INITIALS}
              </div>
              <div className="flex items-center gap-2 text-sm font-medium" aria-live="polite">
                <Loader2 className="h-4 w-4 animate-spin" aria-hidden />
                Connecting to {CONTACT_NAME}…
              </div>
            </div>
          )}

          {/* ACTIVE — overlays on top of the live video */}
          {status === "active" && (
            <>
              {/* Camera-off placeholder */}
              {isCameraOff && (
                <div className="absolute inset-0 flex flex-col items-center justify-center gap-4 bg-black/80 text-white">
                  <div
                    className="flex h-20 w-20 items-center justify-center rounded-full bg-white/15 text-xl font-semibold"
                    aria-hidden
                  >
                    {CONTACT_INITIALS}
                  </div>
                  <p className="text-sm font-medium">Camera off</p>
                </div>
              )}

              {/* Top status row */}
              <div className="pointer-events-none absolute inset-x-0 top-0 flex items-start justify-between p-4">
                <div className="lg-text-scrim flex flex-col">
                  <span className="text-sm font-semibold">{CONTACT_NAME}</span>
                  <span
                    className="font-mono text-xs tabular-nums opacity-90"
                    aria-live="off"
                    aria-label={`Call duration ${formatDuration(seconds)}`}
                  >
                    {formatDuration(seconds)}
                  </span>
                </div>
                <span className="lg-text-scrim flex items-center gap-1.5 rounded-full bg-black/35 px-2.5 py-1 text-[11px] font-medium backdrop-blur-thin">
                  <span className="h-1.5 w-1.5 animate-pulse rounded-full bg-red-500" aria-hidden />
                  Live
                </span>
              </div>

              {/* Self preview (picture-in-picture style label) */}
              {!isCameraOff && (
                <div className="pointer-events-none absolute right-4 top-16 rounded-control bg-black/30 px-2 py-1 backdrop-blur-thin lg-text-scrim">
                  <span className="text-[11px] font-medium">You</span>
                </div>
              )}

              {/* Control bar */}
              <div className="absolute inset-x-0 bottom-0 flex items-center justify-center gap-3 p-4 sm:gap-4 sm:p-6">
                <div className="glass-chrome flex items-center gap-2 rounded-full px-3 py-2 shadow-glass-sm sm:gap-3">
                  <button
                    type="button"
                    onClick={toggleMute}
                    aria-pressed={isMuted}
                    aria-label={isMuted ? "Unmute microphone" : "Mute microphone"}
                    className={cn(
                      "lg-focus glass-interactive flex h-11 w-11 items-center justify-center rounded-full text-foreground transition-colors",
                      isMuted ? "bg-foreground/90 text-background" : "bg-foreground/10",
                    )}
                  >
                    {isMuted ? (
                      <MicOff className="h-5 w-5" aria-hidden />
                    ) : (
                      <Mic className="h-5 w-5" aria-hidden />
                    )}
                  </button>

                  <button
                    type="button"
                    onClick={toggleCamera}
                    aria-pressed={isCameraOff}
                    aria-label={isCameraOff ? "Turn camera on" : "Turn camera off"}
                    className={cn(
                      "lg-focus glass-interactive flex h-11 w-11 items-center justify-center rounded-full text-foreground transition-colors",
                      isCameraOff ? "bg-foreground/90 text-background" : "bg-foreground/10",
                    )}
                  >
                    {isCameraOff ? (
                      <VideoOff className="h-5 w-5" aria-hidden />
                    ) : (
                      <Video className="h-5 w-5" aria-hidden />
                    )}
                  </button>

                  <button
                    type="button"
                    onClick={() => setIsExpanded((v) => !v)}
                    aria-pressed={isExpanded}
                    aria-label={isExpanded ? "Exit full screen" : "Enter full screen"}
                    className="lg-focus glass-interactive flex h-11 w-11 items-center justify-center rounded-full bg-foreground/10 text-foreground"
                  >
                    {isExpanded ? (
                      <Minimize2 className="h-5 w-5" aria-hidden />
                    ) : (
                      <Maximize2 className="h-5 w-5" aria-hidden />
                    )}
                  </button>

                  <button
                    type="button"
                    onClick={endCall}
                    aria-label="End call"
                    className="lg-focus glass-interactive flex h-11 w-11 items-center justify-center rounded-full bg-red-500 text-white shadow-glass-sm hover:bg-red-600"
                  >
                    <PhoneOff className="h-5 w-5" aria-hidden />
                  </button>
                </div>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  )
}

components/apps/github.tsx.content:
"use client"

import { useMemo, useState } from "react"
import {
  Github,
  Star,
  GitFork,
  Users,
  BookMarked,
  ExternalLink,
  AlertCircle,
  RotateCw,
} from "lucide-react"
import { cn } from "@/lib/utils"
import { useApi } from "@/hooks/use-api"
import type { GithubResponse, GithubRepo } from "@/lib/api/types"

interface GitHubProps {
  isDarkMode?: boolean
}

/* ------------------------------------------------------------------ helpers */

function relativeTime(iso: string): string {
  const then = new Date(iso).getTime()
  if (Number.isNaN(then)) return ""
  const diff = Date.now() - then
  const sec = Math.round(diff / 1000)
  const min = Math.round(sec / 60)
  const hr = Math.round(min / 60)
  const day = Math.round(hr / 24)
  const mon = Math.round(day / 30)
  const yr = Math.round(day / 365)
  if (sec < 60) return "just now"
  if (min < 60) return `${min}m ago`
  if (hr < 24) return `${hr}h ago`
  if (day < 30) return `${day}d ago`
  if (mon < 12) return `${mon}mo ago`
  return `${yr}y ago`
}

function compact(n: number): string {
  if (n < 1000) return String(n)
  if (n < 1_000_000) return `${(n / 1000).toFixed(n % 1000 >= 100 ? 1 : 0)}k`
  return `${(n / 1_000_000).toFixed(1)}M`
}

// Common GitHub language colors (subset; falls back to accent for unknowns).
const LANGUAGE_COLORS: Record<string, string> = {
  TypeScript: "#3178c6",
  JavaScript: "#f1e05a",
  Python: "#3572A5",
  Go: "#00ADD8",
  Rust: "#dea584",
  Java: "#b07219",
  "C++": "#f34b7d",
  C: "#555555",
  "C#": "#178600",
  Ruby: "#701516",
  PHP: "#4F5D95",
  Swift: "#F05138",
  Kotlin: "#A97BFF",
  Dart: "#00B4AB",
  HTML: "#e34c26",
  CSS: "#563d7c",
  SCSS: "#c6538c",
  Shell: "#89e051",
  Vue: "#41b883",
  Svelte: "#ff3e00",
  Astro: "#ff5a03",
  Elixir: "#6e4a7e",
  Lua: "#000080",
  "Jupyter Notebook": "#DA5B0B",
  MDX: "#fcb32c",
}

function languageColor(lang: string | null): string {
  if (!lang) return "var(--lg-accent)"
  return LANGUAGE_COLORS[lang] ?? "var(--lg-accent)"
}

// 5-level green scale for the contribution heatmap, per theme.
const GRID_LIGHT = ["#ebedf0", "#9be9a8", "#40c463", "#30a14e", "#216e39"]
const GRID_DARK = ["#21262d", "#0e4429", "#006d32", "#26a641", "#39d353"]

const WEEKDAY_LABELS = ["", "Mon", "", "Wed", "", "Fri", ""]

/* ------------------------------------------------------------------- atoms */

function Stat({
  icon: Icon,
  value,
  label,
}: {
  icon: typeof Star
  value: string
  label: string
}) {
  return (
    <div className="flex flex-col items-center gap-0.5">
      <div className="flex items-center gap-1.5 text-foreground">
        <Icon className="h-4 w-4 text-muted-foreground" aria-hidden />
        <span className="text-base font-semibold tabular-nums">{value}</span>
      </div>
      <span className="text-xs text-muted-foreground">{label}</span>
    </div>
  )
}

function RepoCard({ repo }: { repo: GithubRepo }) {
  return (
    <a
      href={repo.url}
      target="_blank"
      rel="noopener noreferrer"
      className={cn(
        "glass glass-interactive lg-focus group flex h-full flex-col gap-3 rounded-tile p-4 text-left",
        "transition-shadow",
      )}
      aria-label={`Open ${repo.name} on GitHub in a new tab`}
    >
      <div className="flex items-start justify-between gap-2">
        <div className="flex min-w-0 items-center gap-2">
          <BookMarked className="h-4 w-4 shrink-0 text-muted-foreground" aria-hidden />
          <span className="truncate text-sm font-semibold text-foreground">{repo.name}</span>
        </div>
        <ExternalLink
          className="h-3.5 w-3.5 shrink-0 text-muted-foreground opacity-0 transition-opacity group-hover:opacity-100"
          aria-hidden
        />
      </div>

      <p className="line-clamp-2 min-h-[2.5rem] text-xs leading-relaxed text-muted-foreground">
        {repo.description ?? "No description provided."}
      </p>

      <div className="mt-auto flex items-center gap-4 text-xs text-muted-foreground">
        {repo.language && (
          <span className="flex items-center gap-1.5">
            <span
              className="h-2.5 w-2.5 rounded-full"
              style={{ backgroundColor: languageColor(repo.language) }}
              aria-hidden
            />
            <span className="text-foreground/80">{repo.language}</span>
          </span>
        )}
        <span className="flex items-center gap-1 tabular-nums">
          <Star className="h-3.5 w-3.5" aria-hidden />
          {compact(repo.stars)}
        </span>
        <span className="flex items-center gap-1 tabular-nums">
          <GitFork className="h-3.5 w-3.5" aria-hidden />
          {compact(repo.forks)}
        </span>
        {repo.updatedAt && (
          <span className="ml-auto shrink-0">{relativeTime(repo.updatedAt)}</span>
        )}
      </div>
    </a>
  )
}

/* ----------------------------------------------------------- contributions */

function ContributionGrid({
  weeks,
  total,
  isDarkMode,
}: {
  weeks: number[][]
  total: number
  isDarkMode: boolean
}) {
  const palette = isDarkMode ? GRID_DARK : GRID_LIGHT

  // Month labels positioned above week columns.
  const monthLabels = useMemo(() => {
    const out: { col: number; label: string }[] = []
    let lastMonth = -1
    const now = new Date()
    // Approximate the start date: weeks back from today, week 0 = oldest.
    const start = new Date(now)
    start.setDate(start.getDate() - (weeks.length - 1) * 7)
    weeks.forEach((_, col) => {
      const d = new Date(start)
      d.setDate(d.getDate() + col * 7)
      const m = d.getMonth()
      if (m !== lastMonth) {
        lastMonth = m
        out.push({ col, label: d.toLocaleString("en-US", { month: "short" }) })
      }
    })
    return out
  }, [weeks])

  return (
    <div className="glass rounded-tile p-4">
      <div className="mb-3 flex items-baseline justify-between">
        <h2 className="text-sm font-semibold text-foreground">Contributions</h2>
        <span className="text-xs text-muted-foreground tabular-nums">
          {compact(total)} in the last year
        </span>
      </div>

      <div className="flex gap-2 overflow-x-auto pb-1">
        {/* weekday labels */}
        <div
          className="mt-[18px] grid shrink-0 gap-[3px]"
          style={{ gridTemplateRows: "repeat(7, 11px)" }}
          aria-hidden
        >
          {WEEKDAY_LABELS.map((label, i) => (
            <span
              key={i}
              className="h-[11px] text-[9px] leading-[11px] text-muted-foreground"
            >
              {label}
            </span>
          ))}
        </div>

        <div className="min-w-0">
          {/* month labels */}
          <div className="relative mb-1 h-3" aria-hidden>
            {monthLabels.map(({ col, label }) => (
              <span
                key={`${col}-${label}`}
                className="absolute text-[9px] leading-3 text-muted-foreground"
                style={{ left: col * 14 }}
              >
                {label}
              </span>
            ))}
          </div>

          {/* grid: columns = weeks, rows = days */}
          <div className="flex gap-[3px]">
            {weeks.map((week, wi) => (
              <div key={wi} className="grid gap-[3px]" style={{ gridTemplateRows: "repeat(7, 11px)" }}>
                {Array.from({ length: 7 }).map((_, di) => {
                  const level = Math.max(0, Math.min(4, week[di] ?? 0))
                  return (
                    <span
                      key={di}
                      className="h-[11px] w-[11px] rounded-[2px]"
                      style={{ backgroundColor: palette[level] }}
                      title={`${level} contribution${level === 1 ? "" : "s"}`}
                    />
                  )
                })}
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* legend */}
      <div className="mt-3 flex items-center justify-end gap-1.5 text-[10px] text-muted-foreground">
        <span>Less</span>
        {palette.map((c, i) => (
          <span
            key={i}
            className="h-[11px] w-[11px] rounded-[2px]"
            style={{ backgroundColor: c }}
            aria-hidden
          />
        ))}
        <span>More</span>
      </div>
    </div>
  )
}

/* ------------------------------------------------------------------ states */

function LoadingState() {
  return (
    <div className="h-full overflow-y-auto bg-background p-6">
      <div className="mx-auto max-w-3xl animate-pulse space-y-6">
        <div className="glass flex items-center gap-4 rounded-tile p-5">
          <div className="h-16 w-16 shrink-0 rounded-full bg-muted" />
          <div className="flex-1 space-y-2">
            <div className="h-4 w-40 rounded bg-muted" />
            <div className="h-3 w-24 rounded bg-muted" />
            <div className="h-3 w-64 rounded bg-muted" />
          </div>
        </div>
        <div className="grid grid-cols-2 gap-4 sm:grid-cols-4">
          {Array.from({ length: 4 }).map((_, i) => (
            <div key={i} className="glass h-20 rounded-tile" />
          ))}
        </div>
        <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
          {Array.from({ length: 4 }).map((_, i) => (
            <div key={i} className="glass h-28 rounded-tile" />
          ))}
        </div>
        <div className="glass h-40 rounded-tile" />
      </div>
    </div>
  )
}

function ErrorState({ message, onRetry }: { message: string; onRetry: () => void }) {
  return (
    <div className="flex h-full items-center justify-center bg-background p-6">
      <div className="glass flex max-w-sm flex-col items-center gap-3 rounded-tile p-8 text-center">
        <AlertCircle className="h-8 w-8 text-destructive" aria-hidden />
        <h2 className="text-base font-semibold text-foreground">Couldn&apos;t load GitHub</h2>
        <p className="text-sm text-muted-foreground">{message}</p>
        <button
          type="button"
          onClick={onRetry}
          className="lg-focus glass-interactive mt-1 inline-flex items-center gap-2 rounded-control bg-muted px-4 py-2 text-sm font-medium text-foreground"
        >
          <RotateCw className="h-4 w-4" aria-hidden />
          Retry
        </button>
      </div>
    </div>
  )
}

/* ------------------------------------------------------------------- shell */

export default function GitHub({ isDarkMode = true }: GitHubProps) {
  const { data, error, loading, isMock, refetch } = useApi<GithubResponse>(
    "/api/github?user=apple-techie",
  )
  const [avatarFailed, setAvatarFailed] = useState(false)

  if (loading && !data) return <LoadingState />
  if (error && !data) return <ErrorState message={error} onRetry={refetch} />
  if (!data) return <LoadingState />

  const { profile, topRepos, totalStars, contributions } = data
  const avatarSrc = avatarFailed || !profile.avatarUrl ? "/github.png" : profile.avatarUrl

  return (
    <div className="h-full overflow-y-auto bg-background text-foreground">
      <div className="mx-auto max-w-3xl space-y-6 p-6">
        {/* profile header */}
        <header className="glass relative flex flex-col items-start gap-4 rounded-tile p-5 sm:flex-row sm:items-center">
          {isMock && (
            <span
              className="absolute right-3 top-3 flex items-center gap-1 rounded-full bg-muted px-2 py-0.5 text-[10px] font-medium text-muted-foreground"
              title="Showing realistic demo data"
            >
              <span className="h-1.5 w-1.5 rounded-full bg-amber-500" aria-hidden />
              Demo data
            </span>
          )}

          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img
            src={avatarSrc}
            alt={`${profile.name ?? profile.login} avatar`}
            width={72}
            height={72}
            onError={() => setAvatarFailed(true)}
            className="shrink-0 rounded-full border border-border object-cover"
            style={{ height: 72, width: 72 }}
          />

          <div className="min-w-0 flex-1">
            <div className="flex flex-wrap items-center gap-x-2 gap-y-0.5">
              <h1 className="text-lg font-semibold text-foreground">
                {profile.name ?? profile.login}
              </h1>
              <a
                href={profile.url}
                target="_blank"
                rel="noopener noreferrer"
                className="lg-focus inline-flex items-center gap-1 rounded-control text-sm text-muted-foreground hover:text-foreground"
              >
                <Github className="h-3.5 w-3.5" aria-hidden />@{profile.login}
              </a>
            </div>
            {profile.bio && (
              <p className="mt-1.5 max-w-prose text-sm text-muted-foreground">{profile.bio}</p>
            )}
          </div>
        </header>

        {/* stats */}
        <section className="glass grid grid-cols-2 gap-4 rounded-tile p-5 sm:grid-cols-4">
          <Stat icon={Users} value={compact(profile.followers)} label="Followers" />
          <Stat icon={Users} value={compact(profile.following)} label="Following" />
          <Stat icon={BookMarked} value={compact(profile.publicRepos)} label="Repositories" />
          <Stat icon={Star} value={compact(totalStars)} label="Total Stars" />
        </section>

        {/* top repositories */}
        {topRepos.length > 0 && (
          <section>
            <h2 className="mb-3 text-sm font-semibold text-foreground">Top Repositories</h2>
            <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
              {topRepos.map((repo) => (
                <RepoCard key={repo.name} repo={repo} />
              ))}
            </div>
          </section>
        )}

        {/* contribution heatmap */}
        {contributions?.weeks?.length > 0 && (
          <ContributionGrid
            weeks={contributions.weeks}
            total={contributions.total}
            isDarkMode={isDarkMode}
          />
        )}
      </div>
    </div>
  )
}

components/apps/mail.tsx.content:
"use client"

import { useCallback, useEffect, useMemo, useRef, useState } from "react"
import {
  AlertTriangle,
  Archive,
  ChevronLeft,
  Inbox,
  Mail as MailIcon,
  PenSquare,
  RefreshCw,
  Send,
  Star,
  Trash2,
  X,
} from "lucide-react"
import { cn } from "@/lib/utils"
import { useApi } from "@/hooks/use-api"
import type { MailMessage, MailResponse } from "@/lib/api/types"

interface MailProps {
  isDarkMode?: boolean
}

interface MailboxDef {
  id: string
  label: string
  icon: typeof Inbox
}

const MAILBOXES: MailboxDef[] = [
  { id: "Inbox", label: "Inbox", icon: Inbox },
  { id: "Starred", label: "Starred", icon: Star },
  { id: "Sent", label: "Sent", icon: Send },
  { id: "Archive", label: "Archive", icon: Archive },
  { id: "Trash", label: "Trash", icon: Trash2 },
]

const OWNER_EMAIL = "mail@appletechie.dev"

function relativeDate(iso: string): string {
  const then = new Date(iso).getTime()
  if (Number.isNaN(then)) return ""
  const diff = Date.now() - then
  const abs = Math.abs(diff)
  const minute = 60_000
  const hour = 60 * minute
  const day = 24 * hour

  if (abs < minute) return "now"
  if (abs < hour) {
    const m = Math.round(abs / minute)
    return `${m}m`
  }
  if (abs < day) {
    const h = Math.round(abs / hour)
    return `${h}h`
  }
  if (abs < 7 * day) {
    return new Date(then).toLocaleDateString(undefined, { weekday: "short" })
  }
  const sameYear = new Date(then).getFullYear() === new Date().getFullYear()
  return new Date(then).toLocaleDateString(undefined, {
    month: "short",
    day: "numeric",
    ...(sameYear ? {} : { year: "numeric" }),
  })
}

function fullDate(iso: string): string {
  const d = new Date(iso)
  if (Number.isNaN(d.getTime())) return ""
  return d.toLocaleString(undefined, {
    weekday: "short",
    month: "short",
    day: "numeric",
    year: "numeric",
    hour: "numeric",
    minute: "2-digit",
  })
}

function initials(name: string): string {
  const parts = name.trim().split(/\s+/).filter(Boolean)
  if (parts.length === 0) return "?"
  if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase()
  return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase()
}

function DemoPill() {
  return (
    <span
      className="glass-thin inline-flex items-center gap-1.5 rounded-control px-2 py-0.5 text-[11px] font-medium text-muted-foreground"
      title="Showing realistic demo data — no live mail source connected"
    >
      <span className="h-1.5 w-1.5 rounded-full bg-amber-400" aria-hidden />
      Demo data
    </span>
  )
}

function Avatar({ name }: { name: string }) {
  return (
    <div
      className="flex h-9 w-9 shrink-0 items-center justify-center rounded-full bg-muted text-xs font-semibold text-muted-foreground"
      aria-hidden
    >
      {initials(name)}
    </div>
  )
}

/* --------------------------------------------------------------- composer -- */

function Composer({ onClose }: { onClose: () => void }) {
  const [to, setTo] = useState("")
  const [subject, setSubject] = useState("")
  const [body, setBody] = useState("")
  const firstFieldRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    firstFieldRef.current?.focus()
  }, [])

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") onClose()
    }
    window.addEventListener("keydown", onKey)
    return () => window.removeEventListener("keydown", onKey)
  }, [onClose])

  const send = () => {
    const params = new URLSearchParams()
    if (subject) params.set("subject", subject)
    if (body) params.set("body", body)
    const query = params.toString()
    const target = to.trim() || OWNER_EMAIL
    window.location.href = `mailto:${target}${query ? `?${query}` : ""}`
    onClose()
  }

  return (
    <div
      className="absolute inset-0 z-30 flex items-center justify-center p-6"
      role="dialog"
      aria-modal="true"
      aria-label="New message"
    >
      <button
        type="button"
        className="absolute inset-0 cursor-default bg-black/30 backdrop-blur-thin"
        aria-label="Close composer"
        onClick={onClose}
      />
      <div className="lg-flex glass-thick relative z-10 flex w-full max-w-xl flex-col overflow-hidden rounded-sheet shadow-glass-lg">
        <header className="glass-chrome flex items-center justify-between border-b border-border px-4 py-2.5">
          <h2 className="text-sm font-semibold text-foreground">New Message</h2>
          <button
            type="button"
            onClick={onClose}
            aria-label="Close"
            className="lg-focus glass-interactive flex h-7 w-7 items-center justify-center rounded-full text-muted-foreground hover:text-foreground"
          >
            <X className="h-4 w-4" />
          </button>
        </header>

        <div className="flex flex-col gap-px bg-border">
          <label className="flex items-center gap-3 bg-card px-4 py-2.5 text-sm">
            <span className="w-16 shrink-0 text-muted-foreground">To:</span>
            <input
              ref={firstFieldRef}
              type="email"
              value={to}
              onChange={(e) => setTo(e.target.value)}
              placeholder={OWNER_EMAIL}
              className="w-full bg-transparent text-foreground placeholder:text-muted-foreground/60 focus:outline-none"
            />
          </label>
          <label className="flex items-center gap-3 bg-card px-4 py-2.5 text-sm">
            <span className="w-16 shrink-0 text-muted-foreground">Subject:</span>
            <input
              type="text"
              value={subject}
              onChange={(e) => setSubject(e.target.value)}
              placeholder="Subject"
              className="w-full bg-transparent text-foreground placeholder:text-muted-foreground/60 focus:outline-none"
            />
          </label>
        </div>

        <textarea
          value={body}
          onChange={(e) => setBody(e.target.value)}
          placeholder="Write your message…"
          rows={8}
          className="min-h-[160px] resize-none bg-card px-4 py-3 text-sm leading-relaxed text-foreground placeholder:text-muted-foreground/60 focus:outline-none"
        />

        <footer className="glass-chrome flex items-center justify-end gap-2 border-t border-border px-4 py-3">
          <button
            type="button"
            onClick={onClose}
            className="lg-focus glass-interactive rounded-control px-3.5 py-1.5 text-sm font-medium text-foreground"
          >
            Cancel
          </button>
          <button
            type="button"
            onClick={send}
            className="lg-focus glass-interactive glass-tint-accent inline-flex items-center gap-1.5 rounded-control px-3.5 py-1.5 text-sm font-semibold text-white"
          >
            <Send className="h-3.5 w-3.5" />
            Send
          </button>
        </footer>
      </div>
    </div>
  )
}

/* ----------------------------------------------------------------- states -- */

function CenteredState({
  icon: Icon,
  title,
  description,
  action,
}: {
  icon: typeof MailIcon
  title: string
  description?: string
  action?: React.ReactNode
}) {
  return (
    <div className="flex h-full flex-col items-center justify-center gap-3 p-8 text-center">
      <Icon className="h-12 w-12 text-muted-foreground/50" aria-hidden />
      <div>
        <p className="text-sm font-medium text-foreground">{title}</p>
        {description ? <p className="mt-1 text-xs text-muted-foreground">{description}</p> : null}
      </div>
      {action}
    </div>
  )
}

function ListSkeleton() {
  return (
    <ul className="divide-y divide-border" aria-hidden>
      {Array.from({ length: 7 }).map((_, i) => (
        <li key={i} className="flex gap-3 px-4 py-3">
          <div className="h-9 w-9 shrink-0 animate-pulse rounded-full bg-muted" />
          <div className="flex-1 space-y-2">
            <div className="h-3 w-1/3 animate-pulse rounded bg-muted" />
            <div className="h-3 w-2/3 animate-pulse rounded bg-muted" />
            <div className="h-3 w-1/2 animate-pulse rounded bg-muted" />
          </div>
        </li>
      ))}
    </ul>
  )
}

/* --------------------------------------------------------------- reading -- */

function ReadingPane({
  selectedId,
  fallback,
  isDarkMode,
}: {
  selectedId: string | null
  fallback: MailMessage | undefined
  isDarkMode?: boolean
}) {
  void isDarkMode
  const { data, error, loading, refetch } = useApi<MailMessage>(
    selectedId ? `/api/mail/${selectedId}` : null,
  )

  if (!selectedId) {
    return (
      <CenteredState
        icon={MailIcon}
        title="No message selected"
        description="Choose a message from the list to read it here."
      />
    )
  }

  const message = data ?? fallback

  if (loading && !message) {
    return (
      <div className="space-y-4 p-6">
        <div className="h-6 w-2/3 animate-pulse rounded bg-muted" />
        <div className="flex items-center gap-3">
          <div className="h-10 w-10 animate-pulse rounded-full bg-muted" />
          <div className="flex-1 space-y-2">
            <div className="h-3 w-1/3 animate-pulse rounded bg-muted" />
            <div className="h-3 w-1/4 animate-pulse rounded bg-muted" />
          </div>
        </div>
        <div className="space-y-2 pt-4">
          {Array.from({ length: 6 }).map((_, i) => (
            <div key={i} className="h-3 w-full animate-pulse rounded bg-muted" />
          ))}
        </div>
      </div>
    )
  }

  if (error && !message) {
    return (
      <CenteredState
        icon={AlertTriangle}
        title="Couldn’t load this message"
        description={error}
        action={
          <button
            type="button"
            onClick={refetch}
            className="lg-focus glass-interactive inline-flex items-center gap-1.5 rounded-control px-3 py-1.5 text-sm font-medium text-foreground"
          >
            <RefreshCw className="h-3.5 w-3.5" />
            Retry
          </button>
        }
      />
    )
  }

  if (!message) {
    return <CenteredState icon={MailIcon} title="Message not found" />
  }

  return (
    <article className="flex h-full flex-col">
      <header className="border-b border-border px-6 py-4">
        <h1 className="text-lg font-semibold leading-snug text-foreground">{message.subject}</h1>
        <div className="mt-3 flex items-center gap-3">
          <Avatar name={message.from.name} />
          <div className="min-w-0 flex-1">
            <p className="truncate text-sm font-medium text-foreground">{message.from.name}</p>
            <p className="truncate text-xs text-muted-foreground">{message.from.email}</p>
          </div>
          <time
            dateTime={message.date}
            className="shrink-0 text-xs text-muted-foreground"
            title={fullDate(message.date)}
          >
            {fullDate(message.date)}
          </time>
        </div>
      </header>
      <div
        className="flex-1 overflow-y-auto px-6 py-5 text-sm leading-relaxed text-foreground"
        aria-live="polite"
      >
        {message.body.split("\n").map((line, i) => (
          <p key={i} className={cn(line.trim() === "" ? "h-4" : "mb-3 last:mb-0")}>
            {line}
          </p>
        ))}
      </div>
    </article>
  )
}

/* ------------------------------------------------------------------- main -- */

export default function MailApp({ isDarkMode = true }: MailProps) {
  const { data, error, loading, isMock, refetch } = useApi<MailResponse>("/api/mail")

  const [activeMailbox, setActiveMailbox] = useState("Inbox")
  const [selectedId, setSelectedId] = useState<string | null>(null)
  const [starred, setStarred] = useState<Record<string, boolean>>({})
  const [readIds, setReadIds] = useState<Record<string, boolean>>({})
  const [composing, setComposing] = useState(false)
  const [mobilePane, setMobilePane] = useState<"list" | "read">("list")

  const messages = useMemo(() => data?.messages ?? [], [data])

  const isStarred = useCallback(
    (m: MailMessage) => starred[m.id] ?? Boolean(m.starred),
    [starred],
  )
  const isRead = useCallback(
    (m: MailMessage) => readIds[m.id] ?? m.read,
    [readIds],
  )

  const visibleMessages = useMemo(() => {
    if (activeMailbox === "Starred") return messages.filter(isStarred)
    if (activeMailbox === "Inbox") return messages
    // Sent / Archive / Trash have no seeded data — render as empty mailboxes.
    return messages.filter((m) => m.mailbox === activeMailbox)
  }, [messages, activeMailbox, isStarred])

  const unreadCount = useMemo(
    () => messages.filter((m) => !isRead(m)).length,
    [messages, isRead],
  )

  // Default-select the first message once data arrives.
  useEffect(() => {
    if (!selectedId && visibleMessages.length > 0) {
      setSelectedId(visibleMessages[0].id)
    }
  }, [visibleMessages, selectedId])

  // Keep selection valid when switching mailboxes.
  useEffect(() => {
    if (selectedId && !visibleMessages.some((m) => m.id === selectedId)) {
      setSelectedId(visibleMessages[0]?.id ?? null)
    }
  }, [activeMailbox, visibleMessages, selectedId])

  const selectMessage = useCallback((id: string) => {
    setSelectedId(id)
    setReadIds((prev) => ({ ...prev, [id]: true }))
    setMobilePane("read")
  }, [])

  const toggleStar = useCallback((id: string) => {
    setStarred((prev) => {
      const current = prev[id]
      const base = messages.find((m) => m.id === id)
      const fallback = base ? Boolean(base.starred) : false
      return { ...prev, [id]: !(current ?? fallback) }
    })
  }, [messages])

  const onListKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLUListElement>) => {
      if (e.key !== "ArrowDown" && e.key !== "ArrowUp") return
      e.preventDefault()
      const idx = visibleMessages.findIndex((m) => m.id === selectedId)
      const nextIdx =
        e.key === "ArrowDown"
          ? Math.min(visibleMessages.length - 1, idx + 1)
          : Math.max(0, idx - 1)
      const next = visibleMessages[nextIdx]
      if (next) selectMessage(next.id)
    },
    [visibleMessages, selectedId, selectMessage],
  )

  const selectedFallback = useMemo(
    () => messages.find((m) => m.id === selectedId),
    [messages, selectedId],
  )

  return (
    <div className="relative flex h-full bg-background text-foreground">
      {/* Sidebar */}
      <aside className="glass-chrome hidden w-48 shrink-0 flex-col border-r border-border sm:flex">
        <div className="flex items-center justify-between px-4 py-3">
          <button
            type="button"
            onClick={() => setComposing(true)}
            className="lg-focus glass-interactive glass-tint-accent inline-flex flex-1 items-center justify-center gap-1.5 rounded-control px-3 py-1.5 text-sm font-semibold text-white"
          >
            <PenSquare className="h-3.5 w-3.5" />
            Compose
          </button>
        </div>
        <nav className="flex-1 space-y-0.5 overflow-y-auto px-2 pb-3" aria-label="Mailboxes">
          {MAILBOXES.map((box) => {
            const Icon = box.icon
            const active = activeMailbox === box.id
            const badge = box.id === "Inbox" ? unreadCount : 0
            return (
              <button
                key={box.id}
                type="button"
                onClick={() => setActiveMailbox(box.id)}
                aria-current={active ? "page" : undefined}
                className={cn(
                  "lg-focus flex w-full items-center gap-2.5 rounded-control px-2.5 py-1.5 text-sm",
                  active
                    ? "glass-tint-accent font-medium text-foreground"
                    : "text-muted-foreground hover:bg-muted hover:text-foreground",
                )}
              >
                <Icon className="h-4 w-4 shrink-0" aria-hidden />
                <span className="flex-1 truncate text-left">{box.label}</span>
                {badge > 0 ? (
                  <span className="rounded-full bg-[var(--lg-accent)] px-1.5 py-0.5 text-[10px] font-semibold leading-none text-white">
                    {badge}
                  </span>
                ) : null}
              </button>
            )
          })}
        </nav>
        {isMock ? (
          <div className="px-3 pb-3">
            <DemoPill />
          </div>
        ) : null}
      </aside>

      {/* Message list */}
      <section
        className={cn(
          "flex w-full shrink-0 flex-col border-r border-border sm:w-72 md:w-80",
          mobilePane === "read" ? "hidden sm:flex" : "flex",
        )}
      >
        <header className="glass-chrome flex items-center justify-between gap-2 border-b border-border px-4 py-2.5">
          <h2 className="text-sm font-semibold text-foreground">{activeMailbox}</h2>
          <div className="flex items-center gap-1">
            {isMock ? <span className="sm:hidden"><DemoPill /></span> : null}
            <button
              type="button"
              onClick={refetch}
              aria-label="Refresh mailbox"
              className="lg-focus glass-interactive flex h-7 w-7 items-center justify-center rounded-full text-muted-foreground hover:text-foreground"
            >
              <RefreshCw className={cn("h-3.5 w-3.5", loading && "animate-spin")} />
            </button>
            <button
              type="button"
              onClick={() => setComposing(true)}
              aria-label="Compose message"
              className="lg-focus glass-interactive flex h-7 w-7 items-center justify-center rounded-full text-muted-foreground hover:text-foreground sm:hidden"
            >
              <PenSquare className="h-3.5 w-3.5" />
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto">
          {loading && messages.length === 0 ? (
            <ListSkeleton />
          ) : error && messages.length === 0 ? (
            <CenteredState
              icon={AlertTriangle}
              title="Couldn’t load your inbox"
              description={error}
              action={
                <button
                  type="button"
                  onClick={refetch}
                  className="lg-focus glass-interactive inline-flex items-center gap-1.5 rounded-control px-3 py-1.5 text-sm font-medium text-foreground"
                >
                  <RefreshCw className="h-3.5 w-3.5" />
                  Retry
                </button>
              }
            />
          ) : visibleMessages.length === 0 ? (
            <CenteredState
              icon={activeMailbox === "Starred" ? Star : Inbox}
              title={`No messages in ${activeMailbox}`}
              description={
                activeMailbox === "Starred"
                  ? "Star a message to keep it here."
                  : "This mailbox is empty."
              }
            />
          ) : (
            <ul
              role="listbox"
              aria-label={`${activeMailbox} messages`}
              aria-activedescendant={selectedId ? `mail-row-${selectedId}` : undefined}
              tabIndex={0}
              onKeyDown={onListKeyDown}
              className="divide-y divide-border focus:outline-none"
            >
              {visibleMessages.map((m) => {
                const active = m.id === selectedId
                const unread = !isRead(m)
                const star = isStarred(m)
                return (
                  <li
                    key={m.id}
                    id={`mail-row-${m.id}`}
                    role="option"
                    aria-selected={active}
                  >
                    <div
                      className={cn(
                        "group relative flex cursor-pointer gap-3 px-4 py-3 transition-colors",
                        active ? "glass-tint-accent" : "hover:bg-muted",
                      )}
                    >
                      <button
                        type="button"
                        onClick={() => selectMessage(m.id)}
                        className="lg-focus flex min-w-0 flex-1 gap-3 text-left"
                      >
                        <div className="flex w-2 shrink-0 items-start justify-center pt-1.5">
                          {unread ? (
                            <span
                              className="h-2 w-2 rounded-full bg-[var(--lg-accent)]"
                              aria-label="Unread"
                            />
                          ) : null}
                        </div>
                        <div className="min-w-0 flex-1">
                          <div className="flex items-baseline justify-between gap-2">
                            <span
                              className={cn(
                                "truncate text-sm",
                                unread ? "font-semibold text-foreground" : "font-medium text-foreground",
                              )}
                            >
                              {m.from.name}
                            </span>
                            <time
                              dateTime={m.date}
                              className="shrink-0 text-[11px] text-muted-foreground"
                              title={fullDate(m.date)}
                            >
                              {relativeDate(m.date)}
                            </time>
                          </div>
                          <p
                            className={cn(
                              "truncate text-[13px]",
                              unread ? "font-medium text-foreground" : "text-muted-foreground",
                            )}
                          >
                            {m.subject}
                          </p>
                          <p className="truncate text-xs text-muted-foreground">{m.preview}</p>
                        </div>
                      </button>
                      <button
                        type="button"
                        onClick={() => toggleStar(m.id)}
                        aria-label={star ? "Unstar message" : "Star message"}
                        aria-pressed={star}
                        className="lg-focus flex h-6 w-6 shrink-0 items-center justify-center self-center rounded-full text-muted-foreground hover:text-amber-400"
                      >
                        <Star
                          className={cn(
                            "h-4 w-4",
                            star ? "fill-amber-400 text-amber-400" : "",
                          )}
                        />
                      </button>
                    </div>
                  </li>
                )
              })}
            </ul>
          )}
        </div>
      </section>

      {/* Reading pane */}
      <section
        className={cn(
          "min-w-0 flex-1 flex-col bg-card",
          mobilePane === "read" ? "flex" : "hidden sm:flex",
        )}
      >
        <div className="flex items-center gap-2 border-b border-border px-2 py-1.5 sm:hidden">
          <button
            type="button"
            onClick={() => setMobilePane("list")}
            className="lg-focus glass-interactive inline-flex items-center gap-1 rounded-control px-2 py-1 text-sm font-medium text-foreground"
          >
            <ChevronLeft className="h-4 w-4" />
            {activeMailbox}
          </button>
        </div>
        <div className="min-h-0 flex-1">
          <ReadingPane
            selectedId={selectedId}
            fallback={selectedFallback}
            isDarkMode={isDarkMode}
          />
        </div>
      </section>

      {composing ? <Composer onClose={() => setComposing(false)} /> : null}
    </div>
  )
}

components/apps/media-player.tsx.content:
"use client"

import type React from "react"

import { useCallback, useEffect, useMemo, useRef, useState } from "react"
import {
  Play,
  Pause,
  SkipBack,
  SkipForward,
  Volume2,
  Volume1,
  VolumeX,
  Music2,
  ListMusic,
  AlertCircle,
  RotateCcw,
  Loader2,
  ExternalLink,
} from "lucide-react"
import { useApi } from "@/hooks/use-api"
import type { Track, TracksResponse } from "@/lib/api/types"
import { cn } from "@/lib/utils"

export type MediaAccent = "spotify" | "apple"

interface AccentConfig {
  /** brand name shown in the chrome */
  name: string
  /** brand logo in /public */
  logo: string
  /** CSS color used for the seek/volume fill + active accents (canvas/inline only) */
  color: string
  /** subtle wash behind the now-playing artwork */
  wash: string
  /** optional link to the owner's profile on the service */
  profileUrl?: string
}

const ACCENTS: Record<MediaAccent, AccentConfig> = {
  spotify: {
    name: "Spotify",
    logo: "/spotify.png",
    color: "#1db954",
    wash: "from-[#1db954]/25 via-[#1db954]/5 to-transparent",
    profileUrl: "https://open.spotify.com/user/12137031642",
  },
  apple: {
    name: "Music",
    logo: "/letter-d.png",
    color: "#fa2d6c",
    wash: "from-[#fa2d6c]/25 via-[#fa57a6]/8 to-transparent",
  },
}

/** Deterministic gradient seed from a track id, for the fallback artwork tile. */
const FALLBACK_GRADIENTS = [
  "from-rose-400 to-indigo-500",
  "from-amber-400 to-pink-500",
  "from-emerald-400 to-cyan-500",
  "from-violet-500 to-fuchsia-500",
  "from-sky-400 to-blue-600",
  "from-orange-400 to-rose-500",
]

function gradientFor(id: string): string {
  let hash = 0
  for (let i = 0; i < id.length; i++) hash = (hash * 31 + id.charCodeAt(i)) | 0
  return FALLBACK_GRADIENTS[Math.abs(hash) % FALLBACK_GRADIENTS.length]
}

function formatTime(time: number): string {
  if (!Number.isFinite(time) || time < 0) return "0:00"
  const minutes = Math.floor(time / 60)
  const seconds = Math.floor(time % 60)
  return `${minutes}:${seconds < 10 ? "0" : ""}${seconds}`
}

interface ArtworkProps {
  track: Track | undefined
  className?: string
  rounded?: string
}

function Artwork({ track, className, rounded = "rounded-tile" }: ArtworkProps) {
  const [errored, setErrored] = useState(false)
  useEffect(() => setErrored(false), [track?.cover])

  if (track?.cover && !errored) {
    return (
      <img
        src={track.cover || "/placeholder.svg"}
        alt=""
        aria-hidden="true"
        onError={() => setErrored(true)}
        className={cn("h-full w-full object-cover", rounded, className)}
      />
    )
  }

  return (
    <div
      aria-hidden="true"
      className={cn(
        "flex h-full w-full items-center justify-center bg-gradient-to-br text-white/80",
        rounded,
        track ? gradientFor(track.id) : "from-muted to-muted",
        className,
      )}
    >
      <Music2 className="h-1/3 w-1/3" strokeWidth={1.5} />
    </div>
  )
}

export interface MediaPlayerProps {
  isDarkMode?: boolean
  accent: MediaAccent
}

export default function MediaPlayer({ accent }: MediaPlayerProps) {
  const cfg = ACCENTS[accent]
  const { data, error, loading, isMock, refetch } = useApi<TracksResponse>("/api/tracks")
  const tracks = useMemo<Track[]>(() => data?.tracks ?? [], [data])

  const audioRef = useRef<HTMLAudioElement>(null)
  /** set true ONLY when the user explicitly wants playback to begin on the
   *  newly-loaded track (next/prev/select). Consumed inside canplaythrough. */
  const shouldAutoPlayRef = useRef(false)

  const [currentIndex, setCurrentIndex] = useState(0)
  const [isPlaying, setIsPlaying] = useState(false)
  const [currentTime, setCurrentTime] = useState(0)
  const [duration, setDuration] = useState(0)
  const [volume, setVolume] = useState(0.75)
  const [isMuted, setIsMuted] = useState(false)
  const [audioError, setAudioError] = useState<string | null>(null)
  const [isSeeking, setIsSeeking] = useState(false)

  const currentTrack = tracks[currentIndex]

  // Clamp the index if the playlist shrinks between fetches.
  useEffect(() => {
    if (tracks.length > 0 && currentIndex >= tracks.length) {
      setCurrentIndex(0)
    }
  }, [tracks.length, currentIndex])

  const goToTrack = useCallback(
    (index: number, autoPlay: boolean) => {
      if (tracks.length === 0) return
      const next = ((index % tracks.length) + tracks.length) % tracks.length
      shouldAutoPlayRef.current = autoPlay
      setAudioError(null)
      if (next === currentIndex) {
        // Re-selecting the active track toggles playback rather than reloading.
        const audio = audioRef.current
        if (!audio) return
        if (audio.paused) {
          audio.play().catch(() => setIsPlaying(false))
        } else {
          audio.pause()
        }
        return
      }
      setCurrentTime(0)
      setDuration(0)
      setCurrentIndex(next)
    },
    [tracks.length, currentIndex],
  )

  const handleNext = useCallback(() => goToTrack(currentIndex + 1, true), [goToTrack, currentIndex])
  const handlePrev = useCallback(() => {
    // If we're more than 3s into a track, restart it instead of skipping back.
    const audio = audioRef.current
    if (audio && audio.currentTime > 3) {
      audio.currentTime = 0
      return
    }
    goToTrack(currentIndex - 1, true)
  }, [goToTrack, currentIndex])

  const togglePlay = useCallback(() => {
    const audio = audioRef.current
    if (!audio || !currentTrack) return
    setAudioError(null)
    if (audio.paused) {
      shouldAutoPlayRef.current = true
      const p = audio.play()
      if (p) p.catch(() => setIsPlaying(false))
    } else {
      audio.pause()
    }
  }, [currentTrack])

  // Wire the single <audio> element. Re-runs when the source track changes.
  useEffect(() => {
    const audio = audioRef.current
    if (!audio || !currentTrack) return

    const onTime = () => {
      if (!isSeeking) setCurrentTime(audio.currentTime)
    }
    const onLoadedMeta = () => setDuration(audio.duration || currentTrack.durationSec || 0)
    const onPlay = () => setIsPlaying(true)
    const onPause = () => setIsPlaying(false)
    const onEnded = () => {
      if (tracks.length > 1) goToTrack(currentIndex + 1, true)
      else setIsPlaying(false)
    }
    const onCanPlayThrough = () => {
      // Trigger autoplay HERE — never via a setTimeout reading stale state.
      if (shouldAutoPlayRef.current) {
        shouldAutoPlayRef.current = false
        const p = audio.play()
        if (p) p.catch(() => setIsPlaying(false))
      }
    }
    const onError = () => {
      setAudioError("Couldn’t load this track.")
      setIsPlaying(false)
      shouldAutoPlayRef.current = false
    }

    audio.addEventListener("timeupdate", onTime)
    audio.addEventListener("loadedmetadata", onLoadedMeta)
    audio.addEventListener("durationchange", onLoadedMeta)
    audio.addEventListener("play", onPlay)
    audio.addEventListener("pause", onPause)
    audio.addEventListener("ended", onEnded)
    audio.addEventListener("canplaythrough", onCanPlayThrough)
    audio.addEventListener("error", onError)

    audio.load()

    return () => {
      audio.removeEventListener("timeupdate", onTime)
      audio.removeEventListener("loadedmetadata", onLoadedMeta)
      audio.removeEventListener("durationchange", onLoadedMeta)
      audio.removeEventListener("play", onPlay)
      audio.removeEventListener("pause", onPause)
      audio.removeEventListener("ended", onEnded)
      audio.removeEventListener("canplaythrough", onCanPlayThrough)
      audio.removeEventListener("error", onError)
    }
  }, [currentTrack?.src, currentTrack?.id, currentIndex, tracks.length, goToTrack, isSeeking, currentTrack])

  // Keep element volume in sync.
  useEffect(() => {
    const audio = audioRef.current
    if (audio) audio.volume = isMuted ? 0 : volume
  }, [volume, isMuted])

  // Pause + release audio on unmount.
  useEffect(() => {
    const audio = audioRef.current
    return () => {
      if (audio) {
        audio.pause()
        audio.removeAttribute("src")
        audio.load()
      }
    }
  }, [])

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = Number.parseFloat(e.target.value)
    setCurrentTime(value)
  }
  const commitSeek = () => {
    const audio = audioRef.current
    if (audio && Number.isFinite(currentTime)) {
      try {
        audio.currentTime = currentTime
      } catch {
        /* ignore out-of-range seeks */
      }
    }
    setIsSeeking(false)
  }

  const handleVolume = (e: React.ChangeEvent<HTMLInputElement>) => {
    const v = Number.parseFloat(e.target.value)
    setVolume(v)
    setIsMuted(v === 0)
  }

  const seekPct = duration > 0 ? Math.min(100, (currentTime / duration) * 100) : 0
  const volPct = (isMuted ? 0 : volume) * 100
  const fillStyle = (pct: number): React.CSSProperties => ({
    background: `linear-gradient(to right, ${cfg.color} 0%, ${cfg.color} ${pct}%, color-mix(in srgb, currentColor 18%, transparent) ${pct}%, color-mix(in srgb, currentColor 18%, transparent) 100%)`,
  })

  const VolumeIcon = isMuted || volume === 0 ? VolumeX : volume < 0.5 ? Volume1 : Volume2

  /* --------------------------------------------------------- chrome header -- */
  const header = (
    <header className="glass-chrome flex items-center justify-between gap-3 border-b border-border/60 px-4 py-2.5">
      <div className="flex items-center gap-2.5">
        <img src={cfg.logo || "/placeholder.svg"} alt="" aria-hidden="true" className="h-6 w-6 rounded-control" />
        <h1 className="text-sm font-semibold text-foreground">{cfg.name}</h1>
      </div>
      <div className="flex items-center gap-2">
        {isMock && (
          <span
            className="glass-thin inline-flex items-center gap-1.5 rounded-full px-2 py-0.5 text-[11px] font-medium text-muted-foreground"
            title="Served from realistic fallback data"
          >
            <span className="h-1.5 w-1.5 rounded-full" style={{ background: cfg.color }} aria-hidden="true" />
            Demo data
          </span>
        )}
        {cfg.profileUrl && (
          <a
            href={cfg.profileUrl}
            target="_blank"
            rel="noopener noreferrer"
            className="lg-focus inline-flex items-center gap-1.5 rounded-full px-3 py-1 text-xs font-semibold text-white outline-none transition-opacity hover:opacity-90"
            style={{ background: cfg.color }}
          >
            <ExternalLink className="h-3.5 w-3.5" />
            Open in {cfg.name}
          </a>
        )}
      </div>
    </header>
  )

  /* ---------------------------------------------------------------- states -- */
  if (loading) {
    return (
      <div className="flex h-full flex-col bg-background text-foreground">
        {header}
        <div className="flex flex-1 flex-col items-center justify-center gap-4 p-6">
          <div className="h-44 w-44 animate-pulse rounded-tile bg-muted" />
          <div className="h-4 w-40 animate-pulse rounded bg-muted" />
          <div className="h-3 w-28 animate-pulse rounded bg-muted" />
          <Loader2 className="mt-2 h-5 w-5 animate-spin text-muted-foreground" aria-hidden="true" />
          <span className="sr-only">Loading library…</span>
        </div>
      </div>
    )
  }

  if (error) {
    return (
      <div className="flex h-full flex-col bg-background text-foreground">
        {header}
        <div className="flex flex-1 flex-col items-center justify-center gap-3 p-6 text-center">
          <AlertCircle className="h-8 w-8 text-destructive" aria-hidden="true" />
          <p className="max-w-xs text-sm text-muted-foreground">{error}</p>
          <button
            type="button"
            onClick={refetch}
            className="glass-interactive lg-focus inline-flex items-center gap-2 rounded-control px-3.5 py-1.5 text-sm font-medium text-foreground"
          >
            <RotateCcw className="h-4 w-4" aria-hidden="true" />
            Retry
          </button>
        </div>
      </div>
    )
  }

  if (tracks.length === 0) {
    return (
      <div className="flex h-full flex-col bg-background text-foreground">
        {header}
        <div className="flex flex-1 flex-col items-center justify-center gap-3 p-6 text-center">
          <ListMusic className="h-8 w-8 text-muted-foreground" aria-hidden="true" />
          <p className="text-sm font-medium text-foreground">Your library is empty</p>
          <p className="max-w-xs text-xs text-muted-foreground">
            Drop an audio file into <span className="font-mono">/public</span> to start listening.
          </p>
        </div>
      </div>
    )
  }

  /* ------------------------------------------------------------- main view -- */
  return (
    <div className="flex h-full flex-col bg-background text-foreground">
      {header}

      <div className="flex flex-1 flex-col overflow-hidden md:flex-row">
        {/* Now playing */}
        <section className="relative flex flex-1 flex-col items-center justify-center gap-5 p-6">
          <div
            aria-hidden="true"
            className={cn("pointer-events-none absolute inset-0 bg-gradient-to-b", cfg.wash)}
          />
          <div className="relative aspect-square w-44 max-w-[60%] overflow-hidden rounded-tile shadow-glass-lg sm:w-52">
            <Artwork track={currentTrack} />
          </div>

          <div className="relative z-10 max-w-full text-center">
            <h2 className="truncate text-lg font-semibold text-foreground">{currentTrack?.title}</h2>
            <p className="truncate text-sm text-muted-foreground">{currentTrack?.artist}</p>
            {audioError && (
              <p className="mt-1 text-xs text-destructive" role="alert">
                {audioError}
              </p>
            )}
          </div>

          {/* Seek */}
          <div className="relative z-10 w-full max-w-md">
            <input
              type="range"
              min={0}
              max={duration || 1}
              step={0.1}
              value={currentTime}
              onChange={handleSeek}
              onPointerDown={() => setIsSeeking(true)}
              onPointerUp={commitSeek}
              onKeyUp={commitSeek}
              onBlur={() => isSeeking && commitSeek()}
              disabled={!currentTrack}
              aria-label="Seek"
              className="lg-focus h-1.5 w-full cursor-pointer appearance-none rounded-full text-muted-foreground/40 accent-transparent disabled:opacity-50"
              style={fillStyle(seekPct)}
            />
            <div className="mt-1.5 flex justify-between text-[11px] tabular-nums text-muted-foreground">
              <span>{formatTime(currentTime)}</span>
              <span>{formatTime(duration)}</span>
            </div>
          </div>

          {/* Transport */}
          <div className="relative z-10 flex items-center gap-6">
            <button
              type="button"
              onClick={handlePrev}
              aria-label="Previous track"
              className="lg-focus rounded-full p-2 text-muted-foreground transition-colors hover:text-foreground"
            >
              <SkipBack className="h-6 w-6" />
            </button>
            <button
              type="button"
              onClick={togglePlay}
              aria-label={isPlaying ? "Pause" : "Play"}
              className="lg-focus glass-interactive flex h-14 w-14 items-center justify-center rounded-full text-white shadow-glass"
              style={{ background: cfg.color }}
            >
              {isPlaying ? (
                <Pause className="h-7 w-7" fill="currentColor" />
              ) : (
                <Play className="ml-0.5 h-7 w-7" fill="currentColor" />
              )}
            </button>
            <button
              type="button"
              onClick={handleNext}
              aria-label="Next track"
              className="lg-focus rounded-full p-2 text-muted-foreground transition-colors hover:text-foreground"
            >
              <SkipForward className="h-6 w-6" />
            </button>
          </div>

          {/* Volume */}
          <div className="relative z-10 flex w-full max-w-[14rem] items-center gap-2 text-muted-foreground">
            <button
              type="button"
              onClick={() => setIsMuted((m) => !m)}
              aria-label={isMuted ? "Unmute" : "Mute"}
              className="lg-focus rounded-full p-1.5 transition-colors hover:text-foreground"
            >
              <VolumeIcon className="h-4 w-4" />
            </button>
            <input
              type="range"
              min={0}
              max={1}
              step={0.01}
              value={isMuted ? 0 : volume}
              onChange={handleVolume}
              aria-label="Volume"
              className="lg-focus h-1.5 w-full cursor-pointer appearance-none rounded-full accent-transparent"
              style={fillStyle(volPct)}
            />
          </div>
        </section>

        {/* Playlist */}
        <aside className="glass-thin flex w-full shrink-0 flex-col border-t border-border/60 md:w-72 md:border-l md:border-t-0">
          <div className="flex items-center gap-2 px-4 py-3 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
            <ListMusic className="h-3.5 w-3.5" aria-hidden="true" />
            Up Next
            <span className="ml-auto font-normal normal-case tabular-nums">{tracks.length}</span>
          </div>
          <ul className="flex-1 overflow-y-auto px-2 pb-3" role="listbox" aria-label="Playlist">
            {tracks.map((track, index) => {
              const active = index === currentIndex
              return (
                <li key={track.id}>
                  <button
                    type="button"
                    role="option"
                    aria-selected={active}
                    aria-current={active ? "true" : undefined}
                    onClick={() => goToTrack(index, true)}
                    className={cn(
                      "lg-focus group flex w-full items-center gap-3 rounded-control px-2 py-2 text-left transition-colors",
                      active ? "glass-tint-accent" : "hover:bg-muted/60",
                    )}
                  >
                    <div className="relative h-10 w-10 shrink-0 overflow-hidden rounded-control">
                      <Artwork track={track} rounded="rounded-control" />
                      {active && isPlaying && (
                        <span className="absolute inset-0 flex items-center justify-center bg-black/35">
                          <span className="flex h-3 items-end gap-[2px]" aria-hidden="true">
                            <span className="w-[2px] animate-pulse bg-white" style={{ height: "60%" }} />
                            <span className="w-[2px] animate-pulse bg-white [animation-delay:120ms]" style={{ height: "100%" }} />
                            <span className="w-[2px] animate-pulse bg-white [animation-delay:240ms]" style={{ height: "45%" }} />
                          </span>
                        </span>
                      )}
                    </div>
                    <div className="min-w-0 flex-1">
                      <p
                        className={cn(
                          "truncate text-sm font-medium",
                          active ? "text-foreground" : "text-foreground/90",
                        )}
                        style={active ? { color: cfg.color } : undefined}
                      >
                        {track.title}
                      </p>
                      <p className="truncate text-xs text-muted-foreground">{track.artist}</p>
                    </div>
                    {track.durationSec ? (
                      <span className="shrink-0 text-[11px] tabular-nums text-muted-foreground">
                        {formatTime(track.durationSec)}
                      </span>
                    ) : null}
                  </button>
                </li>
              )
            })}
          </ul>
        </aside>
      </div>

      <audio ref={audioRef} src={currentTrack?.src} preload="auto" aria-hidden="true" />
    </div>
  )
}

