            style={{ width: `${loadPct}%` }}
          />
        </div>
        <p className="mt-2 text-xs text-muted-foreground">1m · 5m · 15m load average</p>
      </Card>

      {/* System / build */}
      <Card>
        <Row>
          <Info className="h-4 w-4 text-muted-foreground" />
          <SettingLabel label="macOS" />
