  preview: string
  body: string
  folder: string
  pinned?: boolean
  updatedAt: string
}
export interface NotesResponse {
  notes: Note[]
}

/* ------------------------------------------------------------------ mail -- */
export interface MailMessage {
  id: string
  from: { name: string; email: string }
  subject: string
  preview: string
  body: string
  date: string
  read: boolean
  starred?: boolean
  mailbox: string
}
export interface MailResponse {
  messages: MailMessage[]
  unreadCount: number
}

/* ---------------------------------------------------------------- github -- */
export interface GithubRepo {
  name: string
  description: string | null
  url: string
  language: string | null
  stars: number
  forks: number
  updatedAt: string
}
export interface GithubProfile {
  login: string
  name: string | null
  avatarUrl: string
  bio: string | null
  followers: number
  following: number
  publicRepos: number
  url: string
}
export interface GithubContributions {
  total: number
  /** 53 weeks x 7 days, each 0–4 intensity level */
  weeks: number[][]
}
export interface GithubResponse {
  profile: GithubProfile
  topRepos: GithubRepo[]
  totalStars: number
  contributions: GithubContributions
  updatedAt: string
}

/* --------------------------------------------------------------- weather -- */
export type WeatherCondition = "sunny" | "partly-cloudy" | "cloudy" | "rainy" | "snowy" | "foggy" | "stormy"

export interface WeatherDay {
  day: string
  date: string
  high: number
  low: number
  condition: WeatherCondition
}
export interface WeatherResponse {
  location: { name: string; country?: string; lat: number; lon: number }
  current: {
    tempC: number
    feelsLikeC: number
    condition: WeatherCondition
    conditionLabel: string
    humidity: number
    windKph: number
    sunrise: string
    sunset: string
    isDay: boolean
  }
  forecast: WeatherDay[]
  updatedAt: string
}

/* -------------------------------------------------------------------- fs -- */
export interface FsEntry {
  name: string
  type: "dir" | "file"
  path: string
  size?: number
}
export interface FsDirResponse {
  type: "dir"
  path: string
  entries: FsEntry[]
}
export interface FsFileResponse {
  type: "file"
  path: string
  size: number
  language: string
  content: string
  truncated: boolean
}
export type FsResponse = FsDirResponse | FsFileResponse

